CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
ORANGE = (255, 165, 0)

# Cell states
class CellState(Enum):
    EMPTY = auto()
    FALLING = auto()
    LOCKED = auto()

# Tetromino colors
TETROMINO_COLORS = {
    'I': CYAN,
    'O': YELLOW,
    'T': MAGENTA,
    'S': GREEN,
    'Z': RED,
    'J': BLUE,
    'L': ORANGE
}

def color_for_tetromino(shape_char):
    return TETROMINO_COLORS.get(shape_char, WHITE)

