        return self.cells[y][x]

    def set_cell(self, x, y, state, color):
        self.cells[y][x].state = state
        self.cells[y][x].color = color

    def clear_cell(self, x, y):
        self.set_cell(x, y, CellState.EMPTY, BLACK)

    def lock_tetromino_block(self, x, y, shape_char):
        color = color_for_tetromino(shape_char)
        self.set_cell(x, y, CellState.LOCKED, color)

    def is_valid_move(self, x, y):
        return 0 <= x < self.width and 0 <= y < self.height and self.get_cell(x, y).state == CellState.EMPTY

