    6: {'shape': [['.', '.', '.', '.'],
                   ['.', '.', 'L', '.'],
                   ['L', 'L', 'L', '.'],
                   ['.', '.', '.', '.']], 'color': 'L'}
}

# Tetromino class
class Tetromino:
    def __init__(self, x, y, shape_id):
        self.x = x
        self.y = y
        self.shape = [list(row) for row in TETROMINOS[shape_id]['shape']]
        self.color = TETROMINOS[shape_id]['color']
        self.shape_id = shape_id

    def rotate(self):
