                for x in range(len(self.current_piece.shape[0])):
                    if self.current_piece.shape[y][x]:
                        grid_x = self.current_piece.x + x
                        grid_y = self.current_piece.y + y
                        self.grid.lock_tetromino_block(grid_x, grid_y, self.current_piece.color)
            self.current_piece = None
            self.clear_lines()
            self.find_matches()

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.grid_height):
            if all(self.grid.get_cell(x, y).state == CellState.LOCKED for x in range(self.grid_width)):
                lines_cleared += 1
                for x in range(self.grid_width):
                    self.grid.clear_cell(x, y)
                for yy in range(y - 1, -1, -1):
                    for x in range(self.grid_width):
                        cell = self.grid.get_cell(x, yy)
                        if cell.state == CellState.LOCKED:
                            color = cell.color
                            self.grid.clear_cell(x, yy)
                            self.grid.set_cell(x, yy + 1, CellState.LOCKED, color)
        self.score += lines_cleared ** 2 * 100

    def find_matches(self):
        matches = []
        # Horizontal matches
        for y in range(self.grid_height):
            for x in range(self.grid_width - 2):
                c1 = self.grid.get_cell(x, y).color
                c2 = self.grid.get_cell(x+1, y).color
                c3 = self.grid.get_cell(x+2, y).color
                if self.grid.get_cell(x, y).state == CellState.LOCKED and c1 == c2 == c3:
                    matches.append((x, y))
                    matches.append((x+1, y))
                    matches.append((x+2, y))

