                c2 = self.grid.get_cell(x, y+1).color
                c3 = self.grid.get_cell(x, y+2).color
                if self.grid.get_cell(x, y).state == CellState.LOCKED and c1 == c2 == c3:
                    matches.append((x, y))
                    matches.append((x, y+1))
                    matches.append((x, y+2))

        # Remove duplicate matches
        matches = list(set(matches))

        # Clear matches and update score
        for x, y in matches:
            self.grid.clear_cell(x, y)
            self.score += 50

    def draw_next_piece(self, screen):
