                if self.next_piece.shape[y][x]:
                    rect = pygame.Rect(NEXT_PIECE_X + x * CELL_SIZE * 0.5, NEXT_PIECE_Y + y * CELL_SIZE * 0.5, CELL_SIZE * 0.5, CELL_SIZE * 0.5)
                    pygame.draw.rect(screen, color, rect)
