        screen.blit(text, (SCORE_X, SCORE_Y))

    def draw(self, screen):
        self.grid.draw(screen)
        if self.current_piece:
            self.current_piece.draw(screen)
        self.draw_next_piece(screen)
        self.draw_score(screen)

    def handle_input(self, event):
        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_LEFT:
                self.move_piece_sideways(-1)
            elif event.key == pygame.K_RIGHT:
                self.move_piece_sideways(1)
            elif event.key == pygame.K_DOWN:
                self.move_piece_down()
            elif event.key == pygame.K_UP:
                self.rotate_piece()
            elif event.key == pygame.K_SPACE:
                while self.move_piece_down():
                    pass
                self.lock_piece()

    def game_loop(self, screen, clock):
        fall_speed = 1 #blocks per second
        fall_event = pygame.event.custom_type()
        pygame.time.set_timer(fall_event, int(1000/fall_speed))
        self.spawn_new_piece()
        running = True
        while running:
            screen.fill(BLACK)
            self.draw(screen)

            if self.game_over:
                font = pygame.font.Font(None, 50)
                text = font.render("Game Over", True, WHITE)
                text_rect = text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
                screen.blit(text, text_rect)
                pygame.display.flip()
                pygame.time.wait(3000)
                running = False #or restart the game

            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                if event.type == fall_event:
                    if self.current_piece is None:
                        if not self.spawn_new_piece():
                            self.game_over = True #if spawning fails, game over
                    else:
                        self.move_piece_down()
                self.handle_input(event)

            pygame.display.flip()
            clock.tick(60)

# --- Main ---
if __name__ == '__main__':
    # Set up the screen
    screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
    pygame.display.set_caption("Tetris Bejeweled")
    clock = pygame.time.Clock()

    # Create the game object
    game = Game(GRID_WIDTH, GRID_HEIGHT)
